"use client";

import { useState, useEffect } from "react";
import Link from "next/link";
import { 
  Stethoscope, ClipboardCheck, Hospital, FileText, DollarSign, Brain, Settings,
  ArrowLeft, Plus, Search, AlertTriangle, CheckCircle, Clock, TrendingUp,
  Activity, Users, Calendar, BarChart3
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { FUNSAU_CATEGORIAS } from "@/types/funsau";
import { mockPacientesPM, mockProtocolosPM, statsFunsauPM, PATENTES_PM, UNIDADES_PM } from "@/lib/dados-mock";
import { useRouter } from "next/navigation";

const iconMap: Record<string, React.ReactNode> = {
  Stethoscope: <Stethoscope className="h-8 w-8 text-emerald-500" />,
  ClipboardCheck: <ClipboardCheck className="h-8 w-8 text-blue-500" />,
  Hospital: <Hospital className="h-8 w-8 text-purple-500" />,
  FileText: <FileText className="h-8 w-8 text-amber-500" />,
  DollarSign: <DollarSign className="h-8 w-8 text-green-500" />,
  Brain: <Brain className="h-8 w-8 text-rose-500" />,
  Settings: <Settings className="h-8 w-8 text-slate-500" />,
};

const gradientMap: Record<string, string> = {
  emerald: "from-emerald-500 to-teal-600",
  blue: "from-blue-500 to-indigo-600",
  purple: "from-purple-500 to-violet-600",
  amber: "from-amber-500 to-orange-600",
  green: "from-green-500 to-emerald-600",
  rose: "from-rose-500 to-pink-600",
  slate: "from-slate-500 to-gray-600",
};

const bgMap: Record<string, string> = {
  emerald: "bg-emerald-100 text-emerald-700",
  blue: "bg-blue-100 text-blue-700",
  purple: "bg-purple-100 text-purple-700",
  amber: "bg-amber-100 text-amber-700",
  green: "bg-green-100 text-green-700",
  rose: "bg-rose-100 text-rose-700",
  slate: "bg-slate-100 text-slate-700",
};

// Mock de estatísticas
const statsMock = {
  protocolos_dia: 45,
  em_auditoria: 28,
  aprovados: 156,
  glosados: 12,
  valor_aprovado: 125680.50,
  pendentes_pagamento: 34,
};

export default function FunsauPage() {
  const [cpfBusca, setCpfBusca] = useState("");
  const [loading, setLoading] = useState(false);

  const buscarPaciente = () => {
    if (!cpfBusca) return;
    // Implementar busca
    console.log("Buscando paciente:", cpfBusca);
  };

  return (
    <main className="min-h-screen bg-gradient-to-br from-slate-50 via-white to-emerald-50">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex items-center justify-between h-16">
            <div className="flex items-center gap-4">
              <Link href="/" className="p-2 rounded-lg hover:bg-slate-100 transition-colors">
                <ArrowLeft className="h-5 w-5 text-slate-600" />
              </Link>
              <div className="flex items-center gap-3">
                <div className="p-2 bg-gradient-to-br from-emerald-500 to-teal-600 rounded-xl">
                  <Activity className="h-6 w-6 text-white" />
                </div>
                <div>
                  <h1 className="text-xl font-bold text-slate-900">FUNSAU Saúde</h1>
                  <p className="text-xs text-slate-500">Gestão e Auditoria de Processos Médicos</p>
                </div>
              </div>
            </div>
            
            <div className="flex items-center gap-3">
              <div className="flex items-center gap-2 px-4 py-2 bg-emerald-50 rounded-lg">
                <span className="text-sm text-emerald-700 font-medium">Brasíndice:</span>
                <span className="text-sm text-emerald-900 font-bold">v24.01</span>
              </div>
            </div>
          </div>
        </div>
      </header>

      <div className="max-w-7xl mx-auto px-4 py-8 sm:px-6 lg:px-8">
        {/* Busca Rápida por CPF */}
        <Card className="mb-8 border-emerald-200 bg-emerald-50/50">
          <CardContent className="p-6">
            <div className="flex flex-col md:flex-row items-center gap-4">
              <div className="flex items-center gap-3">
                <div className="p-3 bg-emerald-100 rounded-xl">
                  <Search className="h-6 w-6 text-emerald-600" />
                </div>
                <div>
                  <h3 className="font-bold text-slate-900">Consulta por CPF</h3>
                  <p className="text-sm text-slate-500">Acesse protocolos e histórico do paciente</p>
                </div>
              </div>
              <div className="flex-1 w-full md:w-auto">
                <div className="flex gap-2">
                  <Input 
                    placeholder="Digite o CPF do paciente..."
                    value={cpfBusca}
                    onChange={(e) => setCpfBusca(e.target.value)}
                    className="flex-1 rounded-xl"
                  />
                  <Button 
                    onClick={buscarPaciente}
                    className="bg-emerald-600 hover:bg-emerald-700 rounded-xl"
                  >
                    <Search className="h-4 w-4 mr-2" />
                    Buscar
                  </Button>
                </div>
              </div>
            </div>
          </CardContent>
        </Card>

        {/* Stats Overview */}
        <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 gap-4 mb-10">
          <Card className="border-l-4 border-l-emerald-500">
            <CardContent className="p-4">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm text-slate-500">Protocolos Hoje</p>
                  <p className="text-2xl font-bold text-slate-900">{statsMock.protocolos_dia}</p>
                </div>
                <div className="p-2 bg-emerald-100 rounded-lg">
                  <Activity className="h-5 w-5 text-emerald-600" />
                </div>
              </div>
            </CardContent>
          </Card>

          <Card className="border-l-4 border-l-blue-500">
            <CardContent className="p-4">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm text-slate-500">Em Auditoria</p>
                  <p className="text-2xl font-bold text-slate-900">{statsMock.em_auditoria}</p>
                </div>
                <div className="p-2 bg-blue-100 rounded-lg">
                  <ClipboardCheck className="h-5 w-5 text-blue-600" />
                </div>
              </div>
            </CardContent>
          </Card>

          <Card className="border-l-4 border-l-green-500">
            <CardContent className="p-4">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm text-slate-500">Aprovados</p>
                  <p className="text-2xl font-bold text-slate-900">{statsMock.aprovados}</p>
                </div>
                <div className="p-2 bg-green-100 rounded-lg">
                  <CheckCircle className="h-5 w-5 text-green-600" />
                </div>
              </div>
            </CardContent>
          </Card>

          <Card className="border-l-4 border-l-rose-500">
            <CardContent className="p-4">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm text-slate-500">Glosados</p>
                  <p className="text-2xl font-bold text-slate-900">{statsMock.glosados}</p>
                </div>
                <div className="p-2 bg-rose-100 rounded-lg">
                  <AlertTriangle className="h-5 w-5 text-rose-600" />
                </div>
              </div>
            </CardContent>
          </Card>

          <Card className="border-l-4 border-l-purple-500 col-span-2">
            <CardContent className="p-4">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm text-slate-500">Valor Aprovado (Mês)</p>
                  <p className="text-2xl font-bold text-slate-900">
                    R$ {statsMock.valor_aprovado.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                  </p>
                </div>
                <div className="p-2 bg-purple-100 rounded-lg">
                  <DollarSign className="h-5 w-5 text-purple-600" />
                </div>
              </div>
            </CardContent>
          </Card>
        </div>

        {/* Dados de Demonstração */}
        <div className="mb-8 grid grid-cols-1 lg:grid-cols-2 gap-6">
          {/* Pacientes Recentes */}
          <div>
            <div className="flex items-center justify-between mb-4">
              <h3 className="text-lg font-bold text-slate-900">Pacientes Cadastrados (Demonstração)</h3>
              <span className="text-xs text-amber-600 bg-amber-50 px-2 py-1 rounded-full">Dados fictícios</span>
            </div>
            <div className="space-y-3">
              {mockPacientes.map((pac) => (
                <Card key={pac.id} className="border-l-4 border-l-emerald-400">
                  <CardContent className="p-4">
                    <div className="flex items-center justify-between">
                      <div>
                        <p className="font-semibold text-slate-900">{pac.nome}</p>
                        <p className="text-sm text-slate-500">CPF: {pac.cpf}</p>
                        <p className="text-xs text-slate-400">{pac.patente}</p>
                      </div>
                      <div className="text-right">
                        <p className="text-xs font-bold text-emerald-600">{pac.numero_carteirinha}</p>
                        {pac.condicoes && pac.condicoes.length > 0 && (
                          <div className="mt-1 flex flex-wrap gap-1 justify-end">
                            {pac.condicoes.map((cond, idx) => (
                              <span key={idx} className="text-xs bg-amber-100 text-amber-700 px-2 py-0.5 rounded">
                                {cond}
                              </span>
                            ))}
                          </div>
                        )}
                      </div>
                    </div>
                  </CardContent>
                </Card>
              ))}
            </div>
          </div>

          {/* Protocolos Recentes */}
          <div>
            <div className="flex items-center justify-between mb-4">
              <h3 className="text-lg font-bold text-slate-900">Protocolos Recentes (Demonstração)</h3>
              <span className="text-xs text-amber-600 bg-amber-50 px-2 py-1 rounded-full">Dados fictícios</span>
            </div>
            <div className="space-y-3">
              {mockProtocolos.map((prot) => (
                <Card key={prot.id} className="border-l-4 border-l-blue-400">
                  <CardContent className="p-4">
                    <div className="flex items-center justify-between mb-2">
                      <span className="font-bold text-slate-900">{prot.numero_protocolo}</span>
                      <span className={`text-xs px-2 py-1 rounded-full ${
                        prot.status === 'Liberado' ? 'bg-emerald-100 text-emerald-700' : 
                        prot.status === 'Urgente' ? 'bg-red-100 text-red-700' : 'bg-amber-100 text-amber-700'
                      }`}>{prot.status}</span>
                    </div>
                    <p className="text-sm text-slate-700">{prot.paciente_nome}</p>
                    <p className="text-xs text-slate-500">{prot.tipo_atendimento} - {prot.especialidade}</p>
                    <div className="mt-2 flex items-center justify-between">
                      <span className="text-xs bg-slate-100 text-slate-600 px-2 py-1 rounded">{prot.prioridade}</span>
                      <span className="text-sm font-bold text-emerald-600">
                        R$ {prot.valor_total.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                      </span>
                    </div>
                  </CardContent>
                </Card>
              ))}
            </div>
          </div>
        </div>

        {/* Quick Actions */}
        <div className="flex flex-wrap gap-3 mb-10">
          <Button className="rounded-full bg-gradient-to-r from-emerald-600 to-teal-700">
            <Plus className="h-4 w-4 mr-2" />
            Novo Atendimento
          </Button>
          <Button className="rounded-full bg-gradient-to-r from-blue-600 to-indigo-700">
            <ClipboardCheck className="h-4 w-4 mr-2" />
            Auditoria
          </Button>
          <Button className="rounded-full bg-gradient-to-r from-purple-600 to-violet-700">
            <Hospital className="h-4 w-4 mr-2" />
            Validar Paciente
          </Button>
          <Button variant="outline" className="rounded-full border-amber-200 text-amber-700 hover:bg-amber-50">
            <FileText className="h-4 w-4 mr-2" />
            Upload XML
          </Button>
        </div>

        {/* Módulos */}
        <h2 className="text-2xl font-bold text-slate-900 mb-6">Módulos do Sistema</h2>
        
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {Object.values(FUNSAU_CATEGORIAS).map((cat) => (
            <Link
              key={cat.id}
              href={`/funsau/${cat.id}`}
              className="group relative overflow-hidden rounded-2xl border border-slate-200 bg-white p-6 transition-all duration-300 hover:shadow-xl hover:border-transparent"
            >
              <div className={`absolute top-0 left-0 w-1 h-full bg-gradient-to-b ${gradientMap[cat.cor]}`} />
              
              <div className="flex items-start gap-4">
                <div className={`p-3 rounded-xl ${bgMap[cat.cor]}`}>
                  {iconMap[cat.icon]}
                </div>
                <div className="flex-1">
                  <h3 className="text-lg font-bold text-slate-900 mb-1 group-hover:text-emerald-600 transition-colors">
                    {cat.title}
                  </h3>
                  <p className="text-sm text-slate-500 mb-3">{cat.descricao}</p>
                  
                  <div className="flex flex-wrap gap-2">
                    {cat.secoes.slice(0, 2).map((secao) => (
                      <span key={secao} className="text-xs bg-slate-100 text-slate-600 px-2 py-1 rounded-full">
                        {secao}
                      </span>
                    ))}
                    {cat.secoes.length > 2 && (
                      <span className="text-xs text-slate-400 px-2 py-1">+{cat.secoes.length - 2}</span>
                    )}
                  </div>
                </div>
              </div>
              
              <div className="mt-4 flex items-center text-sm font-medium text-slate-400 group-hover:text-emerald-600 transition-colors">
                Acessar módulo
                <TrendingUp className="h-4 w-4 ml-2 transition-transform group-hover:translate-x-1" />
              </div>
            </Link>
          ))}
        </div>

        {/* Alertas e Pendências */}
        <div className="mt-10 grid grid-cols-1 lg:grid-cols-2 gap-6">
          <Card className="border-amber-200 bg-amber-50/50">
            <CardContent className="p-6">
              <div className="flex items-center gap-3 mb-4">
                <AlertTriangle className="h-5 w-5 text-amber-600" />
                <h3 className="font-bold text-slate-900">Alertas de Auditoria</h3>
              </div>
              <ul className="space-y-3">
                <li className="flex items-center justify-between text-sm">
                  <span className="text-slate-700">Discrepâncias de preço detectadas</span>
                  <span className="font-bold text-amber-600">3</span>
                </li>
                <li className="flex items-center justify-between text-sm">
                  <span className="text-slate-700">Frequência atípica de procedimentos</span>
                  <span className="font-bold text-rose-600">5</span>
                </li>
                <li className="flex items-center justify-between text-sm">
                  <span className="text-slate-700">XMLs com erros de estrutura</span>
                  <span className="font-bold text-amber-600">2</span>
                </li>
              </ul>
            </CardContent>
          </Card>

          <Card className="border-blue-200 bg-blue-50/50">
            <CardContent className="p-6">
              <div className="flex items-center gap-3 mb-4">
                <Clock className="h-5 w-5 text-blue-600" />
                <h3 className="font-bold text-slate-900">Pendências</h3>
              </div>
              <ul className="space-y-3">
                <li className="flex items-center justify-between text-sm">
                  <span className="text-slate-700">Aguardando documentos</span>
                  <span className="font-bold text-blue-600">12</span>
                </li>
                <li className="flex items-center justify-between text-sm">
                  <span className="text-slate-700">Aguardando auditoria prévia</span>
                  <span className="font-bold text-blue-600">8</span>
                </li>
                <li className="flex items-center justify-between text-sm">
                  <span className="text-slate-700">Liberação para pagamento</span>
                  <span className="font-bold text-emerald-600">{statsMock.pendentes_pagamento}</span>
                </li>
              </ul>
            </CardContent>
          </Card>
        </div>
      </div>
    </main>
  );
}
